import org.owasp.encoder.Encode;

import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name: ");
        String userName = "";
        try {
            userName = reader.readLine();
            userName = Encode.forHtml(userName); // Encode user input for HTML context
        } catch (IOException e) {
            e.printStackTrace();
        }

        System.out.println("Hello, " + userName + "!"); // Output sanitized user input
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
